import{_ as n,o as t,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"69. Occupational Health And Safety Workplace Violence","description":"","frontmatter":{"title":"69. Occupational Health And Safety Workplace Violence","eba":"Mental Health Services 2024-2028","topics":["ohs","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/ohs/69-occupational-health-and-safety-workplace-violence.md","filePath":"ebas/mental-health/common-terms/ohs/69-occupational-health-and-safety-workplace-violence.md"}'),s={name:"ebas/mental-health/common-terms/ohs/69-occupational-health-and-safety-workplace-violence.md"};function r(i,e,l,c,p,h){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_69-occupational-health-and-safety-workplace-violence" tabindex="-1">69. Occupational Health And Safety Workplace Violence <a class="header-anchor" href="#_69-occupational-health-and-safety-workplace-violence" aria-label="Permalink to &quot;69. Occupational Health And Safety Workplace Violence&quot;">​</a></h1><p><strong>69.1</strong> OHS Preliminary</p><p><strong>(a)</strong> Relationship to legislation These provisions will be read and interpreted in conjunction with the OHS Act, EO Act, WIRC Act and successors, provided where there is any inconsistency between this Agreement and the legislation referred to above, the legislation prevails to the extent of any inconsistency.</p><p><strong>(b)</strong> Arrangement of this Part K This part is arranged as follows:</p><p><strong>(i)</strong> OHS Preliminary (clause 69 )</p><p><strong>(ii)</strong> OHS Working Group (<a href="/eba/ebas/mental-health/common-terms/ohs/69A-industry-ohs-working-group.html">clause 69A</a>)</p><p><strong>(iii)</strong> OHS Risk Management (<a href="/eba/ebas/mental-health/common-terms/ohs/69B-ohs-risk-management.html">clause 69B</a>)</p><p><strong>(iv)</strong> Prevention and Management of Workplace Injuries (<a href="/eba/ebas/mental-health/common-terms/ohs/69C-incident-reporting-investigation-and-prevention.html">clause 69C</a>)</p><p><strong>(v)</strong> Incident reporting, investigation and prevention (<a href="/eba/ebas/mental-health/common-terms/ohs/69C-incident-reporting-investigation-and-prevention.html">clause 69C</a>)</p><p><strong>(vi)</strong> Designated work groups (<a href="/eba/ebas/mental-health/common-terms/ohs/69D-designated-work-groups.html">clause 69D</a>)</p><p><strong>(vii)</strong> HSRs (<a href="/eba/ebas/mental-health/common-terms/ohs/69E-hsrs.html">clause 69E</a>)</p><p><strong>(viii)</strong> Manual Handling incidents (<a href="/eba/ebas/mental-health/common-terms/ohs/69B-ohs-risk-management.html">Clause 69B.12</a>)</p><p><strong>(ix)</strong> Occupational Violence and Aggression Prevention and Management (<a href="/eba/ebas/mental-health/common-terms/ohs/69F-occupational-violence-and-aggression-prevention-and.html">clause 69F</a>)</p><p><strong>(x)</strong> Hazardous Weather Conditions (see <a href="/eba/ebas/mental-health/common-terms/ohs/69G-hazardous-weather-conditions.html">clause 69G</a>)</p><p><strong>(xi)</strong> Workers’ Compensation, Rehabilitation and Return to Work (Clause 69H)</p><p><strong>(xii)</strong> Prevention of Gendered Violence Including Sexual Harassment (clause 69I).</p><p><strong>(c)</strong> Definitions For the purposes of this Part K of this Agreement:</p><p><strong>(i)</strong> DWG means designated work group as defined under the OHS Act as amended from time to time and may include Employees other than nurses and/or midwives.</p><p><strong>(ii)</strong> Incident means an event or circumstance that led or could have led to unintended or unnecessary harm.</p><p><strong>(iii)</strong> Injury means any physical or mental injury.</p><p><strong>(iv)</strong> Insurer means an authorised agent as defined by the WIRC Act.</p><p><strong>(v)</strong> Workplace means workplace as defined under the OHS Act.</p><p><strong>(vi)</strong> Occupational Violence and Aggression (&#39;OVA&#39;) means any violent, threatening or other abusive behaviour by a person against a worker. It may include, but is not limited to, physical, sexual, emotional, or psychological abuse, bullying (including mobbing) and gendered violence (including sexual harassment).</p><p><strong>(vii)</strong> Occupational Violence Principles includes measures to: <strong>(A)</strong> Improve security <strong>(B)</strong> Identify risk to staff and others <strong>(C)</strong> Include family in the development of consumer care plans <strong>(D)</strong> Ensure violent incidents are reported, investigated and acted upon <strong>(E)</strong> Prevent violence through workplace design <strong>(F)</strong> Provide education and training to mental health and wellbeing staff <strong>(G)</strong> Provide post-incident support <strong>(H)</strong> Apply anti-violence approach across all healthcare disciplines</p><p><strong>69.2</strong> Disputes</p><p><strong>(a)</strong> The dispute resolution (<a href="/eba/ebas/mental-health/common-terms/consultation-disputes/22-disputes-resolution-procedure.html">clause 22</a>) applies to this part.</p><p>Plain language terms: OHS, workplace safety, violence at work, code black, assault.</p>',27)])])}const d=n(s,[["render",r]]);export{m as __pageData,d as default};
